import agno
from PIL import Image

agent = agno.Agent(tools=[...])

@agno.tools
def verify_image_objects(image: Image, claim: str) -> bool:
    # Use actual vision model to detect objects
    from transformers import pipeline
    detector = pipeline('object-detection', model='facebook/detr-resnet-50')
    results = detector(image)
    detected_objects = {r['label'] for r in results}
    return any(obj.lower() in claim.lower() for obj in detected_objects)

response = agent.run('Describe this image', image=image)
if not verify_image_objects(image, response):
    print('Vision hallucination detected')

from pydantic import BaseModel, validator
from typing import List

class Order(BaseModel):
    items: List[str]
    @validator('items')
    def validate_items(cls, v):
        invalid_items = [item for item in v if item not in ['apple', 'banana', 'orange']]
        if invalid_items:
            raise ValueError(f'Hallucinated items: {invalid_items}')
        return v

try:
    result = agent.run(output_model=Order)  # Agno structured output
except ValueError as e:
    if 'Hallucinated items' in str(e):
        print('Structured output hallucination detected')

