from agno import Agent

agent = Agent()
def safe_structured_output(prompt, schema):
    for attempt in range(3):
        try:
            return agent.run(prompt, output_model=schema)
        except ValidationError:
            prompt += f" Strictly follow schema. Attempt {attempt+2}/3"
    return schema.model_construct()  # Safe default

